import Link from 'next/link';

export default async function ProductPage({ params }) {
  // Await params required in Next.js App Router for dynamic segments
  const { slug } = await params;

  // Fetch the single product by its slug
  const res = await fetch(`http://localhost:5000/api/products/${slug}`, { cache: 'no-store' });
  
  if (!res.ok) {
    return (
      <div className="text-center mt-32 min-h-[50vh]">
        <h1 className="text-4xl font-bold text-amber-900 mb-4">Product not found</h1>
        <Link href="/" className="text-amber-600 text-lg font-medium hover:underline flex items-center justify-center gap-2">
          <span>&larr;</span> Return to Shop
        </Link>
      </div>
    );
  }

  const product = await res.json();

  return (
    <div className="bg-white rounded-3xl shadow-xl border border-amber-100 overflow-hidden max-w-5xl mx-auto mt-8 flex flex-col md:flex-row">
      {/* Product Image Side */}
      <div className="md:w-1/2 bg-amber-200 flex items-center justify-center min-h-[400px] md:min-h-[500px]">
        <span className="text-9xl drop-shadow-lg">🍯</span>
      </div>
      
      {/* Product Details Side */}
      <div className="p-8 md:p-12 md:w-1/2 flex flex-col justify-center bg-amber-50/30">
        <div className="text-sm font-black text-amber-600 uppercase tracking-widest mb-3">
          {product.honey_type ? product.honey_type.replace('_', ' ') : 'Premium Honey'}
        </div>
        <h1 className="text-4xl md:text-5xl font-extrabold text-gray-900 mb-6 leading-tight">{product.name}</h1>
        <p className="text-gray-700 mb-8 leading-relaxed text-lg">
          {product.description}
        </p>
        
        <div className="flex items-end gap-4 mb-10 pb-10 border-b border-amber-200">
          <span className="text-5xl font-black text-amber-900">${product.price}</span>
          <span className="text-xl text-gray-500 font-medium mb-1 border-l-2 border-amber-200 pl-4 ml-2">
            {product.weight_g}g
          </span>
        </div>

        {product.stock > 0 ? (
          <button className="w-full bg-amber-600 hover:bg-amber-700 active:scale-[0.98] text-white font-bold text-xl py-5 rounded-2xl shadow-lg transition-all">
            Add to Cart
          </button>
        ) : (
          <button disabled className="w-full bg-gray-200 text-gray-400 font-bold text-xl py-5 rounded-2xl cursor-not-allowed">
            Out of Stock
          </button>
        )}
      </div>
    </div>
  );
}
